'use client';

import Link from 'next/link';
import { useEffect } from 'react';
import { AlertTriangle, ArrowRight, CheckCircle2, ClipboardCheck, ShieldCheck } from 'lucide-react';
import { clsx } from 'clsx';

import { trackEvent } from '@/lib/analytics';
import type {
  GrowthCtaPosition,
  MarketingGrowthEventName,
  MarketingGrowthEventPayload,
} from '@/lib/analytics/growth-events';
import { recordMarketingGrowthEvent } from '@/lib/analytics/growth-events';
import { getConversionMapping } from '@/lib/conversion/registry';

type BridgeIntent = 'rent_increase' | 'section8' | 'money_claim' | 'tenancy_agreement' | string;

export interface CommercialBridgeProps {
  sourcePage: string;
  intent: BridgeIntent;
  headline: string;
  primaryProduct: string;
  primaryHref: string;
  secondaryProduct?: string;
  secondaryHref?: string;
  primaryToolHref?: string;
  ctaPosition: GrowthCtaPosition;
  proofPoints: string[];
  riskMessage: string;
  analyticsEventName?: MarketingGrowthEventName;
  primaryLabel?: string;
  secondaryLabel?: string;
  toolLabel?: string;
  body?: string;
  className?: string;
}

function labelFromProduct(product: string) {
  return product
    .replace(/[_-]+/g, ' ')
    .replace(/\b\w/g, (letter) => letter.toUpperCase());
}

function buildPayload({
  sourcePage,
  intent,
  ctaPosition,
  destination,
  recommendedProduct,
  productClicked,
  toolName,
}: {
  sourcePage: string;
  intent: string;
  ctaPosition: GrowthCtaPosition;
  destination?: string;
  recommendedProduct?: string;
  productClicked?: string;
  toolName?: string;
}): MarketingGrowthEventPayload {
  return {
    sourcePage,
    pagePath: sourcePage,
    pageType: 'guide',
    intent,
    ctaPosition,
    destination,
    recommendedProduct,
    productClicked,
    userType: 'landlord',
    toolName,
  };
}

export function CommercialBridge({
  sourcePage,
  intent,
  headline,
  primaryProduct,
  primaryHref,
  secondaryProduct,
  secondaryHref,
  primaryToolHref,
  ctaPosition,
  proofPoints,
  riskMessage,
  analyticsEventName = 'commercial_bridge_clicked',
  primaryLabel,
  secondaryLabel,
  toolLabel,
  body,
  className,
}: CommercialBridgeProps) {
  const mapping = getConversionMapping(sourcePage);
  const resolvedHeadline = mapping?.headline ?? headline;
  const resolvedBody = mapping?.supportingCopy ?? body;
  const resolvedPrimaryProduct = mapping?.primaryProduct ?? primaryProduct;
  const resolvedPrimaryHref = mapping?.destinationRoute ?? primaryHref;
  const resolvedPrimaryLabel = mapping?.ctaLabel ?? primaryLabel;

  useEffect(() => {
    trackEvent(
      'commercial_bridge_viewed',
      buildPayload({
        sourcePage,
        intent,
        ctaPosition,
        recommendedProduct: primaryProduct,
      }),
      {
        dedupeScope: 'page',
        dedupeKey: `${sourcePage}:${intent}:${ctaPosition}:commercial_bridge_viewed`,
      }
    );
    recordMarketingGrowthEvent('contextual_offer_view', {
      sourcePage,
      pagePath: sourcePage,
      pageType: 'guide',
      intent,
      ctaPosition,
      destination: resolvedPrimaryHref,
      recommendedProduct: resolvedPrimaryProduct,
      price: mapping?.price,
      experimentId: mapping?.trackingId,
    });
  }, [ctaPosition, intent, mapping?.price, mapping?.trackingId, resolvedPrimaryHref, resolvedPrimaryProduct, sourcePage]);

  const trackClick = (destination: string, productClicked?: string, toolName?: string) => {
    trackEvent(
      analyticsEventName,
      buildPayload({
        sourcePage,
        intent,
        ctaPosition,
        destination,
        recommendedProduct: primaryProduct,
        productClicked,
        toolName,
      })
    );

    if (productClicked) {
      trackEvent('product_cta_clicked', {
        sourcePage,
        pagePath: sourcePage,
        pageType: 'guide',
        intent,
        ctaPosition,
        destination,
        recommendedProduct: primaryProduct,
        productClicked,
        userType: 'landlord',
      });
      if (destination === resolvedPrimaryHref) {
        recordMarketingGrowthEvent('contextual_offer_click', {
          sourcePage,
          pagePath: sourcePage,
          pageType: 'guide',
          intent,
          ctaPosition,
          destination,
          recommendedProduct: resolvedPrimaryProduct,
          productClicked,
          price: mapping?.price,
          experimentId: mapping?.trackingId,
        });
      }
    }
  };

  return (
    <section
      className={clsx(
        'my-8 overflow-hidden rounded-lg border border-slate-200 bg-white shadow-sm',
        className
      )}
      data-commercial-bridge={intent}
      data-source-page={sourcePage}
      data-cta-position={ctaPosition}
    >
      <div className="grid gap-0 lg:grid-cols-[minmax(0,1fr)_320px]">
        <div className="p-5 sm:p-6">
          <div className="mb-3 inline-flex items-center gap-2 rounded-full bg-amber-50 px-3 py-1 text-xs font-semibold text-amber-900">
            <AlertTriangle className="h-3.5 w-3.5" aria-hidden="true" />
            {riskMessage}
          </div>
          <h2 className="max-w-3xl text-xl font-bold tracking-normal text-slate-950 sm:text-2xl">
            {resolvedHeadline}
          </h2>
          {resolvedBody ? <p className="mt-3 max-w-3xl text-sm leading-6 text-slate-700">{resolvedBody}</p> : null}
          {mapping ? (
            <p className="mt-3 text-sm font-semibold text-slate-950">
              Fixed price {mapping.price}.{mapping.previewAvailable ? ' Preview available before payment.' : ''}
            </p>
          ) : null}

          <div className="mt-5 flex flex-col gap-3 sm:flex-row sm:flex-wrap">
            {primaryToolHref ? (
              <Link
                href={primaryToolHref}
                onClick={() => trackClick(primaryToolHref, undefined, intent)}
                className="inline-flex min-h-11 items-center justify-center gap-2 rounded-md bg-emerald-600 px-4 py-2 text-sm font-semibold text-white shadow-sm transition hover:bg-emerald-700 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:ring-offset-2"
              >
                <ClipboardCheck className="h-4 w-4" aria-hidden="true" />
                {toolLabel || 'Check risk first'}
                <ArrowRight className="h-4 w-4" aria-hidden="true" />
              </Link>
            ) : null}

            <Link
              href={resolvedPrimaryHref}
              onClick={() => trackClick(resolvedPrimaryHref, resolvedPrimaryProduct)}
              className={clsx(
                'inline-flex min-h-11 items-center justify-center gap-2 rounded-md px-4 py-2 text-sm font-semibold transition focus:outline-none focus:ring-2 focus:ring-slate-900 focus:ring-offset-2',
                primaryToolHref
                  ? 'border border-slate-300 bg-white text-slate-900 hover:border-slate-500 hover:bg-slate-50'
                  : 'bg-slate-950 text-white shadow-sm hover:bg-slate-800'
              )}
            >
              <ShieldCheck className="h-4 w-4" aria-hidden="true" />
              {resolvedPrimaryLabel || labelFromProduct(resolvedPrimaryProduct)}
              <ArrowRight className="h-4 w-4" aria-hidden="true" />
            </Link>

            {secondaryProduct && secondaryHref ? (
              <Link
                href={secondaryHref}
                onClick={() => trackClick(secondaryHref, secondaryProduct)}
                className="inline-flex min-h-11 items-center justify-center gap-2 rounded-md border border-slate-300 bg-white px-4 py-2 text-sm font-semibold text-slate-900 transition hover:border-slate-500 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-slate-900 focus:ring-offset-2"
              >
                {secondaryLabel || labelFromProduct(secondaryProduct)}
              </Link>
            ) : null}
          </div>
        </div>

        <div className="border-t border-slate-200 bg-slate-50 p-5 sm:p-6 lg:border-l lg:border-t-0">
          <p className="text-sm font-semibold text-slate-950">What this helps you do</p>
          <ul className="mt-4 space-y-3">
            {proofPoints.map((point) => (
              <li key={point} className="flex gap-2 text-sm leading-5 text-slate-700">
                <CheckCircle2 className="mt-0.5 h-4 w-4 shrink-0 text-emerald-600" aria-hidden="true" />
                <span>{point}</span>
              </li>
            ))}
          </ul>
        </div>
      </div>
    </section>
  );
}

