      {isSection8 && groundsRequiringPriorNotice.length > 0 && (
        <section className="rounded-[1.5rem] border border-[#e6dcff] bg-white p-5 shadow-[0_14px_34px_rgba(76,29,149,0.06)]">
          <div className="space-y-2">
