            </label>

            <label
              className={`flex items-start rounded-2xl border p-4 transition-all ${
                facts.ground_prerequisite_notice_served === false
                  ? 'border-red-300 bg-red-50 ring-2 ring-red-100'
                  : 'border-gray-200 bg-white hover:border-gray-300'
