/**
 * Analytics Tracking Utilities
 *
 * Provides helper functions for tracking events in:
 * - Google Analytics 4 (GA4)
 * - Google Ads conversion tracking
 * - Facebook Pixel
 * - Vercel Analytics (via @vercel/analytics)
 *
 * Type definitions are in src/types/gtag.d.ts
 */

// Re-export Vercel Analytics tracking functions
export {
  trackWizardPreviewViewed,
  trackCheckoutStarted,
  trackPaymentSuccessLanded,
  trackDocumentDownloadClicked,
  trackCaseArchived,
  trackFreeToolViewed,
  trackValidatorCompleted,
  trackUpsellClicked,
  trackEvent as trackVercelEvent,
} from './analytics/track';

import {
  getResolvedAnalyticsDispatchOptions,
  hasTrackedAnalyticsEvent,
  markTrackedAnalyticsEvent,
  type AnalyticsDispatchOptions,
} from './analytics/ga4-dispatch';
import {
  isMarketingGrowthEventName,
  recordMarketingGrowthEvent,
  type MarketingGrowthEventPayload,
} from './analytics/growth-events';
import { normalizeWizardStep } from './analytics/wizard-step-taxonomy';
import { getWizardAttribution } from './wizard/wizardAttribution';

const ANALYTICS_RETRY_DELAY_MS = 500;
const ANALYTICS_MAX_RETRY_ATTEMPTS = 60;

/**
 * Track a custom event in both Google Analytics and Facebook Pixel
 */
export function trackEvent(
  eventName: string,
  eventParams?: Record<string, any>,
  dispatchOptions?: AnalyticsDispatchOptions
): void {
  trackEventInternal(eventName, eventParams, dispatchOptions, {
    retryAttempt: 0,
    recordGrowthEvent: true,
  });
}

function trackEventInternal(
  eventName: string,
  eventParams: Record<string, any> | undefined,
  dispatchOptions: AnalyticsDispatchOptions | undefined,
  options: { retryAttempt: number; recordGrowthEvent: boolean }
): void {
  if (options.recordGrowthEvent && isMarketingGrowthEventName(eventName)) {
    recordMarketingGrowthEvent(eventName, eventParams as MarketingGrowthEventPayload);
  }

  const hasGoogleTracking =
    typeof window !== 'undefined' && typeof window.gtag === 'function';
  const hasFacebookTracking =
    typeof window !== 'undefined' && typeof window.fbq === 'function';

  if (!hasGoogleTracking && !hasFacebookTracking) {
    if (
      typeof window !== 'undefined' &&
      options.retryAttempt < ANALYTICS_MAX_RETRY_ATTEMPTS
    ) {
      window.setTimeout(() => {
        trackEventInternal(eventName, eventParams, dispatchOptions, {
          retryAttempt: options.retryAttempt + 1,
          recordGrowthEvent: false,
        });
      }, ANALYTICS_RETRY_DELAY_MS);
    }
    return;
  }

  const resolved = getResolvedAnalyticsDispatchOptions(eventName, eventParams, dispatchOptions);
  if (
    resolved.dedupeScope !== 'none' &&
    resolved.dedupeKey &&
    hasTrackedAnalyticsEvent(resolved.dedupeKey)
  ) {
    return;
  }

  // Google Analytics / Google Ads
  if (hasGoogleTracking) {
    window.gtag('event', eventName, resolved.eventParams);
  }

  // Facebook Pixel - map common events
  if (hasFacebookTracking) {
    const fbEventName = mapToFacebookEvent(eventName);
    if (fbEventName) {
      window.fbq('track', fbEventName, resolved.eventParams);
    }
  }

  if (resolved.dedupeScope !== 'none' && resolved.dedupeKey) {
    markTrackedAnalyticsEvent(resolved.dedupeKey);
  }
}

export function trackEventOnce(
  eventName: string,
  eventParams?: Record<string, any>,
  dispatchOptions?: AnalyticsDispatchOptions
): void {
  trackEvent(eventName, eventParams, dispatchOptions);
}

/**
 * Map GA4 event names to Facebook standard events
 */
function mapToFacebookEvent(gaEventName: string): string | null {
  const eventMap: Record<string, string> = {
    page_view: 'PageView',
    view_item: 'ViewContent',
    add_to_cart: 'AddToCart',
    begin_checkout: 'InitiateCheckout',
    purchase: 'Purchase',
    lead: 'Lead',
    sign_up: 'CompleteRegistration',
    search: 'Search',
  };
  return eventMap[gaEventName.toLowerCase()] || null;
}

export interface PageViewTrackingContext {
  title?: string;
  location?: string;
  pageType?: string;
  product?: string;
  jurisdiction?: string;
  route?: string;
  source?: string;
  topic?: string;
  caseId?: string;
  stepName?: string;
  stepGroup?: string;
  stepIndex?: number;
  totalSteps?: number;
  paymentStatus?: string;
}

function removeUndefinedValues<T extends Record<string, any>>(value: T): T {
  return Object.fromEntries(
    Object.entries(value).filter(([, entryValue]) => entryValue !== undefined)
  ) as T;
}

function resolvePageLocation(path: string, explicitLocation?: string): string | undefined {
  if (explicitLocation) return explicitLocation;
  if (typeof window === 'undefined') return undefined;
  if (/^https?:\/\//i.test(path)) return path;

  const normalisedPath = path.startsWith('/') ? path : `/${path}`;
  return `${window.location.origin}${normalisedPath}`;
}

/**
 * Track a page view in Google Analytics.
 *
 * Private/session pages may pass a case-specific page path when we need
 * realtime funnel debugging for individual cases.
 */
export function trackPageView(path: string, context: PageViewTrackingContext = {}): void {
  if (typeof window !== 'undefined' && window.gtag) {
    window.gtag('event', 'page_view', removeUndefinedValues({
      page_path: path,
      page_location: resolvePageLocation(path, context.location),
      page_title: context.title || document.title,
      page_type: context.pageType,
      product: context.product,
      jurisdiction: context.jurisdiction,
      route: context.route,
      source: context.source,
      topic: context.topic,
      case_id: context.caseId,
      step_name: context.stepName,
      step_group: context.stepGroup,
      step_index: context.stepIndex,
      total_steps: context.totalSteps,
      payment_status: context.paymentStatus,
    }));
  }
}

/**
 * Attribution data for purchase tracking
 */
export interface PurchaseAttribution {
  landing_path?: string;
  utm_source?: string;
  utm_medium?: string;
  utm_campaign?: string;
  utm_term?: string;
  utm_content?: string;
  referrer?: string;
  jurisdiction?: string;
  product_type?: string;
}

/**
 * Track a purchase/transaction in Google Analytics and Facebook Pixel
 *
 * @param transactionId - Unique transaction/order ID
 * @param value - Transaction value
 * @param currency - Currency code (default: GBP)
 * @param items - Array of purchased items
 * @param attribution - Optional attribution data for campaign tracking
 */
export function trackPurchase(
  transactionId: string,
  value: number,
  currency: string = 'GBP',
  items?: Array<{
    item_id: string;
    item_name: string;
    item_category?: string;
    price: number;
    quantity?: number;
  }>,
  attribution?: PurchaseAttribution
): void {
  // Google Analytics / Google Ads - include attribution in event
  if (typeof window !== 'undefined' && window.gtag) {
    window.gtag('event', 'purchase', {
      transaction_id: transactionId,
      value,
      currency,
      items,
      // Attribution data for GA4 custom dimensions
      landing_path: attribution?.landing_path,
      utm_source: attribution?.utm_source,
      utm_medium: attribution?.utm_medium,
      utm_campaign: attribution?.utm_campaign,
      utm_term: attribution?.utm_term,
      utm_content: attribution?.utm_content,
      referrer: attribution?.referrer,
      jurisdiction: attribution?.jurisdiction,
      product_type: attribution?.product_type,
    });
  }

  // Facebook Pixel - include attribution in custom data
  if (typeof window !== 'undefined' && window.fbq) {
    window.fbq('track', 'Purchase', {
      value,
      currency,
      content_ids: items?.map(i => i.item_id) || [],
      content_name: items?.map(i => i.item_name).join(', ') || '',
      content_type: 'product',
      // Attribution for Facebook custom data
      ...(attribution && {
        landing_path: attribution.landing_path,
        utm_source: attribution.utm_source,
        utm_campaign: attribution.utm_campaign,
      }),
    });
  }

  recordMarketingGrowthEvent('purchase_completed', {
    productClicked: attribution?.product_type || items?.[0]?.item_id,
    destination: typeof window !== 'undefined' ? window.location.pathname : undefined,
    userType: 'landlord',
  });
  recordMarketingGrowthEvent('payment_succeeded', {
    pagePath: typeof window !== 'undefined' ? window.location.pathname : undefined,
    productSlug: attribution?.product_type || items?.[0]?.item_id,
    recommendedProduct: attribution?.product_type || items?.[0]?.item_id,
    price: value,
    campaign: attribution?.utm_campaign,
    trafficSource: attribution?.utm_source,
  });
}

