/**
 * Track product view
 */
export function trackProductView(
  productId: string,
  productName: string,
  category?: string,
  price?: number,
  context: ProductViewTrackingContext = {}
): void {
  recordMarketingGrowthEvent('product_page_viewed', {
    sourcePage: context.sourcePage || context.pagePath,
    pagePath: context.pagePath,
    pageType: context.pageType || 'product_page',
    intent: context.intent || productId,
    productClicked: productId,
    destination: context.pagePath || (typeof window !== 'undefined' ? window.location.pathname : undefined),
    userType: context.userType || 'landlord',
  });

  trackEvent('view_item', {
    currency: 'GBP',
    value: price || 0,
    items: [
      {
        item_id: productId,
        item_name: productName,
        item_category: category,
        price: price || 0,
      },
    ],
  });
}

/**
 * Track wizard/checkout start
 */
export function trackBeginCheckout(
  productId: string,
  productName: string,
  value: number,
  caseId?: string
): void {
  recordMarketingGrowthEvent('checkout_started', {
    productClicked: productId,
    userType: 'landlord',
  });
  recordMarketingGrowthEvent('checkout_opened', {
    pagePath: typeof window !== 'undefined' ? window.location.pathname : undefined,
    productSlug: productId,
    recommendedProduct: productId,
    price: value,
  });

  // Google Analytics
  if (typeof window !== 'undefined' && window.gtag) {
    window.gtag('event', 'begin_checkout', {
      currency: 'GBP',
      value,
      case_id: caseId,
      items: [
        {
          item_id: productId,
          item_name: productName,
          price: value,
        },
      ],
    });
  }

  // Facebook Pixel
  if (typeof window !== 'undefined' && window.fbq) {
    window.fbq('track', 'InitiateCheckout', {
      value,
      currency: 'GBP',
      content_ids: [productId],
      content_name: productName,
      content_type: 'product',
    });
  }
}

