/**
 * Track when a user completes a wizard step/section
 */
export function trackWizardStepComplete(params: {
  product: string;
  jurisdiction: string;
  step: string;
  stepIndex?: number;
  totalSteps?: number;
  caseId?: string;
}): void {
  const normalizedStep = normalizeWizardStep(params.step);
  const basePayload = {
    event_category: 'wizard',
    product: params.product,
    jurisdiction: params.jurisdiction,
    step_name: params.step,
    step_group: normalizedStep.stepGroup,
    step_index: params.stepIndex ?? 0,
    total_steps: params.totalSteps ?? 0,
  };

  trackEvent('wizard_step_complete', {
    ...basePayload,
  }, {
    family: 'wizard_step_complete',
    variant: 'canonical',
    dedupeScope: params.caseId ? 'case' : 'session',
    dedupeKey: `${params.caseId || 'session'}:${normalizedStep.stepGroup}`,
  });

  trackEvent(normalizedStep.normalizedEventName, {
    ...basePayload,
  }, {
    family: 'wizard_step_complete',
    variant: 'derived',
    dedupeScope: params.caseId ? 'case' : 'session',
    dedupeKey: `${params.caseId || 'session'}:${normalizedStep.stepGroup}`,
  });
  recordMarketingGrowthEvent('builder_step_completed', {
    pagePath: typeof window !== 'undefined' ? window.location.pathname : '/wizard/flow',
    productSlug: params.product,
    recommendedProduct: params.product,
    builderStep: normalizedStep.stepGroup,
  });
}

function buildWizardStepVirtualPagePath(product: string, stepGroup: string): string {
  const safeProduct = product
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_]+/g, '_')
    .replace(/^_+|_+$/g, '') || 'unknown_product';
  const safeStepGroup = stepGroup
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_]+/g, '_')
    .replace(/^_+|_+$/g, '') || 'unknown_step';

  return `/wizard/flow/${safeProduct}/${safeStepGroup}`;
}

/**
 * Track when a user views a wizard step/section.
 */
export function trackWizardStepView(params: {
  product: string;
  jurisdiction: string;
  step: string;
  stepIndex?: number;
  totalSteps?: number;
  caseId?: string;
  src?: string;
  topic?: string;
  utm_source?: string;
  utm_medium?: string;
  utm_campaign?: string;
  landing_url?: string;
  first_seen_at?: string;
}): void {
  const normalizedStep = normalizeWizardStep(params.step);
  const basePayload = {
    event_category: 'wizard',
    product: params.product,
    jurisdiction: params.jurisdiction,
    step_name: params.step,
    step_group: normalizedStep.stepGroup,
    step_index: params.stepIndex ?? 0,
    total_steps: params.totalSteps ?? 0,
    source: params.src || 'direct',
    topic: params.topic || 'general',
    utm_source: params.utm_source,
    utm_medium: params.utm_medium,
    utm_campaign: params.utm_campaign,
    landing_url: params.landing_url,
    first_seen_at: params.first_seen_at,
  };
  const dedupeKey = `${params.caseId || 'session'}:${normalizedStep.stepGroup}`;

  trackEvent('wizard_step_view', {
    ...basePayload,
  }, {
    family: 'wizard_step_view',
    variant: 'canonical',
    dedupeScope: params.caseId ? 'case' : 'session',
    dedupeKey,
  });

  trackEvent(normalizedStep.normalizedViewEventName, {
    ...basePayload,
  }, {
    family: 'wizard_step_view',
    variant: 'derived',
    dedupeScope: params.caseId ? 'case' : 'session',
    dedupeKey,
  });
  recordMarketingGrowthEvent('builder_step_viewed', {
    pagePath: typeof window !== 'undefined' ? window.location.pathname : '/wizard/flow',
    productSlug: params.product,
    recommendedProduct: params.product,
    builderStep: normalizedStep.stepGroup,
    trafficSource: params.src || 'direct',
    campaign: params.utm_campaign,
  });

  const virtualPageViewDedupeKey = `wizard_step_page_view::${dedupeKey}`;
  if (!hasTrackedAnalyticsEvent(virtualPageViewDedupeKey)) {
    markTrackedAnalyticsEvent(virtualPageViewDedupeKey);
    trackPageView(buildWizardStepVirtualPagePath(params.product, normalizedStep.stepGroup), {
      title: `Wizard - ${params.product} - ${normalizedStep.stepGroup}`,
      pageType: 'wizard_step',
      product: params.product,
      jurisdiction: params.jurisdiction,
      route: normalizedStep.stepGroup,
      source: params.src || 'direct',
      topic: params.topic || 'general',
      caseId: params.caseId,
      stepName: params.step,
      stepGroup: normalizedStep.stepGroup,
      stepIndex: params.stepIndex ?? 0,
      totalSteps: params.totalSteps ?? 0,
    });
  }
}

export type MarketingPageType = 'homepage' | 'entry_page' | 'guide' | 'product_page';

export type MarketingCtaPosition =
  | 'hero'
  | 'selector'
  | 'route_card'
  | 'quick_answer'
  | 'section'
  | 'final'
  | 'support'
  | 'top'
  | 'mid'
  | 'bottom'
  | 'faq';

function getMarketingAttributionParams() {
  if (typeof window === 'undefined') {
    return {
      source: 'direct',
      landing_path: undefined,
      landing_url: undefined,
      utm_source: undefined,
      utm_medium: undefined,
      utm_campaign: undefined,
      first_seen_at: undefined,
    };
  }

  const attribution = getWizardAttribution();

  return {
    source: attribution.src || 'direct',
    landing_path: attribution.landing_path,
    landing_url: attribution.landing_url,
    utm_source: attribution.utm_source,
    utm_medium: attribution.utm_medium,
    utm_campaign: attribution.utm_campaign,
    first_seen_at: attribution.first_seen_at,
  };
}

export function trackHomepageSelectorView(params: { pagePath: string }): void {
  const attribution = getMarketingAttributionParams();

  trackEvent(
    'homepage_selector_view',
    {
      page_path: params.pagePath,
      page_type: 'homepage',
      source: attribution.source,
      landing_path: attribution.landing_path,
      landing_url: attribution.landing_url,
      utm_source: attribution.utm_source,
      utm_medium: attribution.utm_medium,
      utm_campaign: attribution.utm_campaign,
      first_seen_at: attribution.first_seen_at,
    },
    {
      dedupeScope: 'page',
      dedupeKey: `homepage_selector_view:${params.pagePath}`,
    }
  );
}

export function trackMarketingCtaClick(params: {
  eventName:
    | 'homepage_primary_cta_click'
    | 'homepage_selector_option_click'
    | 'entry_page_primary_cta_click'
    | 'entry_page_secondary_cta_click'
    | 'product_route_chosen';
  pagePath: string;
  pageType: MarketingPageType;
  ctaLabel: string;
  destinationPath: string;
  ctaPosition: MarketingCtaPosition;
  routeIntent?: string;
  product?: string;
}): void {
  const attribution = getMarketingAttributionParams();

  trackEvent(params.eventName, {
    page_path: params.pagePath,
    page_type: params.pageType,
    cta_label: params.ctaLabel,
    cta_position: params.ctaPosition,
    destination_path: params.destinationPath,
    route_intent: params.routeIntent,
    product: params.product,
    source: attribution.source,
    landing_path: attribution.landing_path,
    landing_url: attribution.landing_url,
    utm_source: attribution.utm_source,
    utm_medium: attribution.utm_medium,
    utm_campaign: attribution.utm_campaign,
    first_seen_at: attribution.first_seen_at,
  });

  if (params.product || params.destinationPath.startsWith('/products/')) {
    recordMarketingGrowthEvent('product_cta_clicked', {
      sourcePage: params.pagePath,
      pageType: params.pageType,
      intent: params.routeIntent,
      ctaPosition: params.ctaPosition,
      destination: params.destinationPath,
      productClicked: params.product,
      userType: 'landlord',
